// Извлекаем все карточки лотов с ценами, продавцами, описанием и отзывами
const items = document.querySelectorAll('.tc-item');
const results = [];
items.forEach(el => {
  const title = el.querySelector('.tc-desc-text')?.innerText?.trim() || '';
  const price = el.querySelector('.tc-price div')?.innerText?.trim() || '';
  const seller = el.querySelector('.media-user-name')?.innerText?.trim() || '';
  const reviews = el.querySelector('.rating-num')?.innerText?.trim() || '';
  results.push({ title, price, seller, reviews });
});
JSON.stringify(results.slice(0, 30));

// Все лоты с отзывами и более подробной информацией
const items = document.querySelectorAll('.tc-item');
const results = [];
items.forEach(el => {
  const title = el.querySelector('.tc-desc-text')?.innerText?.trim() || '';
  const price = el.querySelector('.tc-price div')?.innerText?.trim() || '';
  const seller = el.querySelector('.media-user-name')?.innerText?.trim() || '';
  const reviews = el.querySelector('.tc-user .text-nowrap')?.innerText?.trim() || '';
  const orders = el.querySelector('.tc-user .text-muted')?.innerText?.trim() || '';
  const online = el.querySelector('.media-user-online')?.innerText?.trim() || '';
  results.push({ title, price, seller, reviews, orders });
});
JSON.stringify(results);

var items = Array.from(document.querySelectorAll('.tc-item'));
var out = items.map(function(el) {
  return [
    (el.querySelector('.tc-desc-text')||{}).innerText||'',
    (el.querySelector('.tc-price div')||{}).innerText||'',
    (el.querySelector('.media-user-name')||{}).innerText||'',
    (el.querySelector('.tc-user .text-nowrap')||{}).innerText||''
  ].join(' | ');
});
out.join('\n');

var cards = document.querySelectorAll('.tc-item');
var lines = [];
for (var i = 0; i < cards.length; i++) {
  var t = cards[i].querySelector('.tc-desc-text');
  var p = cards[i].querySelector('.tc-price');
  var s = cards[i].querySelector('.media-user-name');
  var r = cards[i].querySelector('.rating-num');
  lines.push((t ? t.innerText : '-') + ' ~~ ' + (p ? p.innerText : '-') + ' ~~ ' + (s ? s.innerText : '-') + ' ~~ ' + (r ? r.innerText : 'нет'));
}
lines.join('\n');

// Смотрим структуру первой карточки
var card = document.querySelector('[class*="card"]');
card ? card.innerText.slice(0, 400) : 'не найдено';

// Ищем элементы с ценами (₽ или руб)
var all = Array.from(document.querySelectorAll('*'));
var withPrice = all.filter(function(el) {
  return el.children.length === 0 && el.innerText && el.innerText.match(/\d+[\s,.]?\d*\s*[₽р]/);
});
withPrice.slice(0, 10).map(function(el) {
  return el.className + ': ' + el.innerText.trim();
}).join('\n');

// Ищем все варианты/опции с ценами
var opts = document.querySelectorAll('[class*="option"], [class*="variant"], select option, [data-price]');
var result = Array.from(opts).slice(0,20).map(function(o){
  return (o.textContent||'').trim().slice(0,100) + ' | price attr: ' + (o.getAttribute('data-price')||o.value||'');
});
result.join('\n');

var opts = document.querySelectorAll('[data-price]');
Array.from(opts).slice(0,10).map(function(o){
  return 'text: ' + (o.innerText||'').trim().slice(0,80) + ' | data-price: ' + o.getAttribute('data-price') + ' | data-value: ' + o.getAttribute('data-value') + ' | all attrs: ' + Array.from(o.attributes).map(function(a){return a.name+'='+a.value}).join(', ');
}).join('\n');

// Ищем лейблы опций
var labels = document.querySelectorAll('label[for], .item-option, .product-option-item, [class*="service-option"], [class*="radio"]');
Array.from(labels).slice(0,15).map(function(l){
  return l.innerText.trim().slice(0,120);
}).join('\n---\n');

// Кликаем на опцию PRO X5
var labels = document.querySelectorAll('label');
var proLabel = Array.from(labels).find(function(l){ return l.innerText.indexOf('PRO X5') !== -1; });
if(proLabel) { proLabel.click(); 'clicked: ' + proLabel.innerText.trim().slice(0,80); } else { 'не найдено'; }

// Читаем цену после клика на PRO X5
var priceEl = document.querySelector('.goods-buy-price, .price-current, [class*="price"], .buy-price, #buy-price');
var allPrices = Array.from(document.querySelectorAll('[class*="price"]')).map(function(el){
  return el.className + ': ' + (el.innerText||'').trim().slice(0,50);
}).filter(function(s){ return s.indexOf('₽') !== -1 || s.match(/\d{3,}/); });
allPrices.slice(0,10).join('\n');

var labels = document.querySelectorAll('label');
var proLabel = Array.from(labels).find(function(l){ return l.innerText.indexOf('PRO X5') !== -1 || l.innerText.indexOf('Pro X5') !== -1; });
if(proLabel) { proLabel.click(); 'clicked: ' + proLabel.innerText.trim().slice(0,100); } else { 
  // Показываем все лейблы
  Array.from(labels).map(function(l){ return l.innerText.trim().slice(0,80); }).filter(function(s){ return s.length > 2; }).slice(0,10).join('\n');
}

var allPrices = Array.from(document.querySelectorAll('[class*="price"]')).map(function(el){
  return (el.innerText||'').trim().slice(0,50);
}).filter(function(s){ return s.indexOf('₽') !== -1; });
// Также статистика продавца
var seller = (document.querySelector('[class*="seller"], .seller-name, .goods-seller') || {innerText:''}).innerText.trim().slice(0,100);
var sales = (document.querySelector('.goods-sold, [class*="sold"]') || {innerText:''}).innerText.trim().slice(0,80);
allPrices.slice(0,5).join(' | ') + '\nПродавец: ' + seller + '\nПродажи: ' + sales;
